import { DragDropModule } from '@angular/cdk/drag-drop';
import { DatePipe } from '@angular/common';
import {
    Component,
    Input,
    OnInit,
    computed,
    inject,
    input,
    output,
} from '@angular/core';
import { MatIconButton } from '@angular/material/button';
import { MatIcon } from '@angular/material/icon';
import { MatListModule } from '@angular/material/list';
import { MatProgressBarModule } from '@angular/material/progress-bar';
import { MatProgressSpinnerModule } from '@angular/material/progress-spinner';
import { MatTooltip } from '@angular/material/tooltip';
import { TranslatePipe } from '@ngx-translate/core';
import { PortalStatus, PortalStatusService } from 'services';
import { PlaylistMeta } from 'shared-interfaces';

@Component({
    selector: 'app-playlist-item',
    templateUrl: './playlist-item.component.html',
    styleUrls: ['./playlist-item.component.scss'],
    imports: [
        DatePipe,
        DragDropModule,
        MatIconButton,
        MatIcon,
        MatListModule,
        MatProgressBarModule,
        MatProgressSpinnerModule,
        MatTooltip,
        TranslatePipe,
    ],
})
export class PlaylistItemComponent implements OnInit {
    @Input() item!: PlaylistMeta;
    readonly showActions = input(true);
    readonly isDraggable = input(false);
    readonly isSelected = input(false);
    readonly isRefreshing = input(false);
    readonly isDeleting = input(false);
    readonly busyMessage = input('');
    readonly busyProgress = input<number | null>(null);
    readonly canCancelBusyAction = input(false);
    readonly isBusy = computed(() => this.isRefreshing() || this.isDeleting());

    readonly editPlaylistClicked = output<PlaylistMeta>();
    readonly playlistClicked = output<string>();
    readonly refreshClicked = output<PlaylistMeta>();
    readonly removeClicked = output<string>();
    readonly cancelBusyActionClicked = output<void>();

    portalStatus: PortalStatus = 'unavailable';
    private readonly portalStatusService = inject(PortalStatusService);

    readonly isElectron = !!window.electron;

    async ngOnInit() {
        await this.checkPortalStatus();
    }

    private async checkPortalStatus() {
        if (this.item.serverUrl && this.item.username && this.item.password) {
            this.portalStatus = await this.portalStatusService.checkPortalStatus(
                this.item.serverUrl,
                this.item.username,
                this.item.password
            );
        }
    }

    getStatusClass(): string {
        return this.portalStatusService.getStatusClass(this.portalStatus);
    }

    getStatusIcon(): string {
        return this.portalStatusService.getStatusIcon(this.portalStatus);
    }

    onPlaylistClick(): void {
        if (this.isBusy()) {
            return;
        }

        this.playlistClicked.emit(this.item._id);
    }
}

@if (playlistsData(); as data) {
    @if (data.playlists.length === 0) {
        @if (data.totalCount === 0) {
            <!-- Welcome state: no playlists at all -->
            <app-empty-state
                [type]="'welcome'"
                (addPlaylistClicked)="onAddPlaylist()"
            />
        } @else {
            <!-- No results state: search/filter returned nothing -->
            <app-empty-state [type]="'no-results'" />
        }
    } @else {
        <mat-nav-list
            class="playlists-list"
            cdkDropList
            [cdkDropListDisabled]="!isCustomSortActive()"
            (cdkDropListDropped)="drop($event, data.playlists)"
        >
            @for (
                item of data.playlists;
                track item._id;
                let last = $last
            ) {
                <app-playlist-item
                    [item]="item"
                    [isSelected]="activePlaylistId() === item._id"
                    [showActions]="!sidebarMode()"
                    [isDraggable]="isCustomSortActive()"
                    [isRefreshing]="isRefreshPending(item._id)"
                    [isDeleting]="isDeletePending(item._id)"
                    [busyMessage]="getBusyMessage(item)"
                    [busyProgress]="getBusyProgress(item._id)"
                    [canCancelBusyAction]="canCancelBusyOperation(item)"
                    (editPlaylistClicked)="openInfoDialog($event)"
                    (playlistClicked)="getPlaylist(item)"
                    (refreshClicked)="refreshPlaylist($event)"
                    (removeClicked)="removeClicked(item)"
                    (cancelBusyActionClicked)="cancelBusyOperation(item)"
                />
            }
        </mat-nav-list>
    }
}

