:host {
    display: block;
    width: 100%;
    container-type: inline-size;
}

.channel-list-item {
    width: 100%;
    min-height: 68px;
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 8px 10px 8px 12px;
    border: 1px solid transparent;
    border-radius: 12px;
    background: transparent;
    color: inherit;
    cursor: pointer;
    box-sizing: border-box;
    overflow: hidden;
    transition:
        background 0.15s ease,
        border-color 0.15s ease,
        box-shadow 0.18s ease,
        transform 0.18s ease,
        color 0.15s ease;

    &:hover {
        background: color-mix(in srgb, currentColor 8%, transparent);
    }

    &.active {
        background: linear-gradient(
            135deg,
            var(--app-selection-surface-strong),
            var(--app-selection-surface)
        );
        border-color: var(--app-selection-border);
        color: var(--app-selection-color);
        box-shadow:
            inset 0 0 0 1px var(--app-selection-border),
            0 12px 20px -18px var(--app-selection-glow);
        transform: translateY(-1px);
    }

    &.compact {
        min-height: 52px;
        padding-block: 7px;
    }
}

.drag-icon {
    flex-shrink: 0;
    cursor: move;
    opacity: 0.46;
}

.channel-content {
    min-width: 0;
