mat-list-item {
    cursor: pointer;
    min-height: 68px;
    border-radius: 8px !important;
    margin: 2px 0;
    border: 1px solid transparent;
    --mdc-list-list-item-leading-icon-color: currentColor;
    transition:
        background 0.15s ease,
        border-color 0.15s ease,
        box-shadow 0.18s ease,
        transform 0.18s ease,
        color 0.15s ease;


    &:hover {
        background: color-mix(in srgb, currentColor 8%, transparent) !important;
    }

    &.selected {
        background: linear-gradient(
            135deg,
            var(--app-selection-surface-strong),
            var(--app-selection-surface)
        ) !important;
        border-color: var(--app-selection-border) !important;
        color: var(--app-selection-color) !important;
        box-shadow:
            inset 0 0 0 1px var(--app-selection-border),
            0 12px 20px -18px var(--app-selection-glow);
        transform: translateY(-1px);

        .meta,
        .upload-type-icon,
        .drag-icon,
        .action-buttons button,
        .action-buttons mat-icon {
            color: inherit !important;
        }

        .status-dot {
            border-color: color-mix(
                in srgb,
                var(--app-selection-surface-strong) 85%,
                transparent
            );
        }
    }

    &.is-busy {
        cursor: progress;
    }
}

.mat-list-base {
    padding-top: 0 !important;
}

[matListItemTitle] {
    font-size: 0.96rem !important;
    font-weight: 600;
    letter-spacing: -0.01em;
    line-height: 1.2;
}

.meta {
    font-size: 0.82rem !important;
    color: var(--mat-sys-on-surface-variant);
    opacity: 0.84;
    margin-top: 2px !important;
    line-height: 1.2;
}

.busy-state {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 12px;
    font-size: 0.7rem !important;
    color: var(--app-selection-border, #8aa4c8);
    margin-top: 4px !important;
}

.busy-state__message {
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.busy-state__value {
    opacity: 0.8;
}

.busy-state__bar {
    margin-top: 4px !important;
}

.cdk-drag-preview {
    box-sizing: border-box;
    border-radius: 8px;
    box-shadow:
        0 8px 24px rgba(0, 0, 0, 0.25),
        0 4px 12px rgba(0, 0, 0, 0.15),
        0 2px 6px rgba(0, 0, 0, 0.1);
    opacity: 0.9;
}

.cdk-drag-placeholder {
    opacity: 0;
}

.cdk-drag-animating {
    transition: transform 300ms cubic-bezier(0.4, 0, 0.2, 1);
}

.drag-icon {
    cursor: move;
    margin-right: 0;
    opacity: 0.46;
    transition: opacity 0.15s ease;

    &:hover {
        opacity: 1;
    }
}

.action-buttons {
    align-self: center !important;
    display: flex;
    align-items: center;
    gap: 2px;

    button {
        width: 34px;
        height: 34px;
        border-radius: 10px;
        color: inherit;
        opacity: 0.76;
        transition:
            opacity 0.15s ease,
            background-color 0.15s ease,
            transform 0.15s ease;

        &:hover {
            opacity: 1;
            background: color-mix(in srgb, currentColor 10%, transparent) !important;
            transform: translateY(-1px);
        }

        mat-icon {
            width: 20px;
            height: 20px;
            font-size: 20px;
        }

        &:disabled {
            transform: none;
            opacity: 0.38;
        }
    }
}

.action-spinner {
    display: block;
    margin: 0 auto;
}

.icon-container {
    position: relative;
    display: inline-flex;

    .upload-type-icon {
        opacity: 0.75;
        transition: opacity 0.15s ease;
    }

